const setPlant = async (organizationId) => {
  const deptId = this.getVarSystem("deptIds").split(",")[0];
  let plantId = "";
  const hasPlant = this.getValue("plant_id");

  if (!hasPlant) {
    if (deptId === organizationId) {
      const resPlant = await db
        .collection("blade_dept")
        .where({ parent_id: deptId })
        .get();

      if (!resPlant || resPlant.data.length === 0) {
        plantId = deptId;
      } else {
        plantId = "";
        this.disabled("table_gr", true);
      }
    } else {
      plantId = deptId;
    }
  }
  console.log(hasPlant, "hasPlant");
  this.setData({
    organization_id: organizationId,
    ...(!hasPlant ? { plant_id: plantId } : {}),
    gr_received_by: this.getVarGlobal("nickname"),
  });
};

const fetchReceivedQuantity = async () => {
  const tableGR = this.getValue("table_gr") || [];
  const status = this.getValue("gr_status");
  const currentGRNo = this.getValue("gr_no");

  const resPOLineData = await Promise.all(
    tableGR.map((item) =>
      db
        .collection("purchase_order_2ukyuanr_sub")
        .doc(item.po_line_item_id)
        .get(),
    ),
  );

  const poLineItemData = resPOLineData.map((response) => response.data[0]);

  const updatedTableGR = await Promise.all(
    tableGR.map(async (item, index) => {
      const poLine = poLineItemData[index];
      const orderQty = poLine ? poLine.quantity || 0 : 0;
      const receivedQty = poLine ? poLine.received_qty || 0 : 0;

      let initialReceivedQty = receivedQty; // Only count Received GRs by default
      let toReceivedQty = orderQty - receivedQty;

      // Special handling when editing a Created GR
      if (status === "Created" && currentGRNo) {
        // When editing Created GR, ignore other Created GRs in the form
        // Warnings only appear when saving (not in form display)

        // initial_received_qty = ONLY received_qty from PO (Received GRs only)
        initialReceivedQty = receivedQty;
        // to_received_qty = orderQty - receivedQty - current GR qty
        const currentGRQty = item.received_qty || 0;
        toReceivedQty = orderQty - receivedQty - currentGRQty;
      }

      return {
        ...item,
        initial_received_qty: initialReceivedQty,
        to_received_qty: toReceivedQty,
      };
    }),
  );

  this.setData({ table_gr: updatedTableGR });
};

const viewSerialNumber = async () => {
  const tableGR = this.getValue("table_gr");
  tableGR.forEach((gr, index) => {
    if (gr.is_serialized_item === 1) {
      this.display(`table_gr.select_serial_number`);
      this.disabled(`table_gr.${index}.received_qty`, true);
    } else {
      this.disabled(`table_gr.${index}.received_qty`, false);
    }
  });
};

const viewBaseQty = async () => {
  const tableGR = this.getValue("table_gr");
  tableGR.forEach((gr) => {
    if (gr.item_uom !== gr.base_item_uom) {
      this.display([
        "table_gr.ordered_qty_uom",
        "table_gr.base_ordered_qty",
        "table_gr.base_ordered_qty_uom",
        "table_gr.to_received_qty_uom",
        "table_gr.base_received_qty_uom",
        "table_gr.base_received_qty",
        "table_gr.base_item_uom",
      ]);
    }
  });
};

const displayAssignedTo = async () => {
  const plant = await this.getValue("plant_id");

  const resPutAwaySetup = await db
    .collection("putaway_setup")
    .where({
      plant_id: plant,
      is_deleted: 0,
      movement_type: "Good Receiving",
    })
    .get();

  const setup =
    resPutAwaySetup && resPutAwaySetup.data.length > 0
      ? resPutAwaySetup.data[0]
      : null;

  setTimeout(() => {
    if (setup && setup.putaway_required === 1) {
      console.log("resPutaway", resPutAwaySetup.data);
      this.display("assigned_to");
    } else {
      this.hide("assigned_to");
    }

    if (setup && setup.show_hu === 1) {
      this.display(["table_gr.select_hu", "table_gr.view_hu"]);
    } else {
      this.hide(["table_gr.select_hu", "table_gr.view_hu"]);
    }
  }, 30);
};

const hideSerialNumberRecordTab = () => {
  setTimeout(() => {
    const tableSerialNumber = this.getValue("table_sn_records");
    if (!tableSerialNumber || tableSerialNumber.length === 0) {
      const tabSelector =
        '.el-drawer[role="dialog"] .el-tabs__item.is-top#tab-serial_number_records[tabindex="-1"][aria-selected="false"]';
      const tab = document.querySelector(tabSelector);

      if (tab) {
        tab.style.display = "none";
      } else {
        const fallbackTab = document.querySelector(
          '.el-drawer[role="dialog"] .el-tabs__item#tab-serial_number_records',
        );
        if (fallbackTab) {
          fallbackTab.style.display = "none";
        } else {
          console.log("Completion tab not found");
        }
      }

      const inactiveTabSelector =
        '.el-drawer[role="dialog"] .el-tabs__item.is-top[tabindex="-1"]:not(#tab-serial_number_records)';
      const inactiveTab = document.querySelector(inactiveTabSelector);
      if (inactiveTab) {
        inactiveTab.setAttribute("aria-disabled", "true");
        inactiveTab.classList.add("is-disabled");
      }
    }
  }, 10); // Small delay to ensure DOM is ready
};

const displayManufacturingAndExpiredDate = async (status, pageStatus) => {
  const tableGR = this.getValue("table_gr");
  if (tableGR.length === 0) return;
  if (pageStatus === "Edit" || pageStatus === "Add") {
    if (status === "Draft") {
      for (const [index, item] of tableGR.entries()) {
        if (item.item_batch_no !== "-") {
          await this.display([
            "table_gr.manufacturing_date",
            "table_gr.expired_date",
          ]);
          await this.disabled(
            [
              `table_gr.${index}.manufacturing_date`,
              `table_gr.${index}.expired_date`,
            ],
            false,
          );
        } else {
          await this.disabled(
            [
              `table_gr.${index}.manufacturing_date`,
              `table_gr.${index}.expired_date`,
            ],
            true,
          );
        }
      }
    } else {
      for (const [index, item] of tableGR.entries()) {
        if (item.item_batch_no !== "-") {
          await this.display([
            "table_gr.manufacturing_date",
            "table_gr.expired_date",
          ]);
        }
      }
    }
  } else {
    for (const [index, item] of tableGR.entries()) {
      if (item.item_batch_no !== "-") {
        await this.display([
          "table_gr.manufacturing_date",
          "table_gr.expired_date",
        ]);
      }
    }
  }
};

const checkAccIntegrationType = async (organizationId) => {
  if (organizationId) {
    const resAI = await db
      .collection("accounting_integration")
      .where({ organization_id: organizationId })
      .get();

    if (resAI && resAI.data.length > 0) {
      const aiData = resAI.data[0];
      this.setData({ acc_integration_type: aiData.acc_integration_type });
    }
  }
};

(async () => {
  try {
    const status = await this.getValue("gr_status");

    const pageStatus = this.isAdd
      ? "Add"
      : this.isEdit
        ? "Edit"
        : this.isView
          ? "View"
          : (() => {
              throw new Error("Invalid page status");
            })();

    let organizationId = this.getVarGlobal("deptParentId");
    if (organizationId === "0") {
      organizationId = this.getVarSystem("deptIds").split(",")[0];
    }

    this.setData({ page_status: pageStatus });

    switch (pageStatus) {
      case "Add":
        this.setData({ gr_date: new Date().toISOString().split("T")[0] });
        this.display(["draft_status"]);
        this.hide("button_completed");
        await setPlant(organizationId);
        await checkAccIntegrationType(organizationId);
        await displayAssignedTo();
        await hideSerialNumberRecordTab();
        if (this.getValue("plant_id")) {
          this.disabled("reference_doc", false);
          console.log("trigger func_processGRLineItem");
          await this.triggerEvent("func_processGRLineItem");
          await this.triggerEvent("onChange_Supplier");
        }

        break;

      case "Edit":
        await disabledEditField(status);
        await displayAddress();
        await showStatusHTML(status);
        await fetchReceivedQuantity();
        await viewSerialNumber();
        await viewBaseQty();
        await displayAssignedTo();
        await checkAccIntegrationType(organizationId);
        await hideSerialNumberRecordTab();
        await displayManufacturingAndExpiredDate(status, pageStatus);
        if (status === "Draft" || status === "Created") {
          await this.triggerEvent("onChange_plant");
          this.hide("button_completed");
        } else {
          this.disabled("assigned_to", true);
        }

        const fromConvert = this.getValue("from_convert");
        this.setData({ previous_status: status });
        if (fromConvert === "Yes") {
          console.log("trigger func_processGRLineItem");
          await this.triggerEvent("func_processGRLineItem");
          await this.triggerEvent("onChange_Supplier");
        }
        break;

      case "View":
        await displayAddress();
        await showStatusHTML(status);
        await isViewMode();
        await viewBaseQty();
        await displayAssignedTo();
        await hideSerialNumberRecordTab();
        await displayManufacturingAndExpiredDate(status, pageStatus);
        break;
    }
  } catch (error) {
    this.$message.error(error);
    console.error(error);
  }
})();

setTimeout(async () => {
  const maxRetries = 10;
  const interval = 500;
  for (let i = 0; i < maxRetries; i++) {
    const op = await this.onDropdownVisible(
      "gr_no_type",
      true,
    );
    if (op != null) break;
    await new Promise((resolve) => setTimeout(resolve, interval));
  }
  function getDefaultItem(arr) {
    return arr?.find((item) => item?.item?.is_default === 1);
  }
  var params = this.getComponent("gr_no");
  const { options } = params;

  const optionsData = this.getOptionData("gr_no_type") || [];
  const defaultData = getDefaultItem(optionsData);
  if (options?.canManualInput) {
    this.setOptionData("gr_no_type", [
      { label: "Manual Input", value: -9999 },
      ...optionsData,
    ]);
    if (this.isAdd) {
      this.setData({
        gr_no_type: defaultData ? defaultData.value : -9999,
      });
    }
  } else if (defaultData) {
    if (this.isAdd) {
      this.setData({ gr_no_type: defaultData.value });
    }
  }
}, 200);

(async () => {
  let purchaseOrderIDs = this.getValue("purchase_order_id");
  console.log(purchaseOrderIDs);

  if (!purchaseOrderIDs || purchaseOrderIDs.length === 0) {
    this.setData({
      table_gr: [],
      purchase_order_number: "",
      po_id: [],
    });
    return;
  }

  const plantId = this.getValue("plant_id");
  purchaseOrderIDs = Array.isArray(purchaseOrderIDs)
    ? purchaseOrderIDs
    : [purchaseOrderIDs];

  this.setData({
    purchase_order_number: "",
    table_gr: [],
    po_id: [],
  });

  let tableGR = [];
  let purchaseOrderNumber = [];
  let poId = [];

  // get bin location
  const resBinLocation = await db
    .collection("bin_location")
    .field("id")
    .where({ plant_id: plantId, is_deleted: 0, is_default: 1 })
    .get();

  // get putaway setup
  const resPutAwaySetup = await db
    .collection("putaway_setup")
    .where({
      plant_id: plantId,
      is_deleted: 0,
      movement_type: "Good Receiving",
    })
    .get();

  const putawaySetup = resPutAwaySetup?.data[0] || null;

  const defaultBinLocation = resBinLocation?.data[0]?.id || "";

  if (purchaseOrderIDs.length > 0) {
    for (const [index, purchaseOrderId] of purchaseOrderIDs.entries()) {
      // get PO header data
      const resPOHeader = await db
        .collection("purchase_order")
        .field("purchase_order_no,table_po")
        .where({ id: purchaseOrderId })
        .get();

      if (!resPOHeader || resPOHeader.data.length === 0) return;
      const poHeaderData = resPOHeader.data[0];

      for (const poLineItemData of poHeaderData.table_po) {
        // get Item data
        const resItem = await db
          .collection("Item")
          .field(
            "receiving_inspection,item_batch_management,batch_number_genaration,material_costing_method"
          )
          .where({ id: poLineItemData.item_id })
          .get();

        if (!resItem || resItem.data.length === 0) return;
        const itemData = resItem.data[0];

        // map GR data
        const newTableGrRecord = {
          item_id: poLineItemData.item_id,
          item_name: poLineItemData.item_name,
          item_desc: poLineItemData.item_desc,
          more_desc: poLineItemData.more_desc,
          ordered_qty: poLineItemData.quantity,
          inspection_required:
            itemData.receiving_inspection === 1 ? "Yes" : "No",
          to_received_qty: 0.0,
          received_qty: parseFloat(
            (
              poLineItemData.quantity - (poLineItemData.received_qty || 0)
            ).toFixed(3)
          ),
          item_uom: poLineItemData.quantity_uom,
          location_id: defaultBinLocation,
          item_batch_no:
            itemData?.item_batch_management === 0
              ? "-"
              : itemData?.batch_number_genaration ===
                "According To System Settings"
              ? "Auto-generated batch number"
              : "",
          inv_category: "",
          line_po_no: poHeaderData.purchase_order_no,
          initial_received_qty: parseFloat(
            (poLineItemData.received_qty || 0).toFixed(3)
          ),
          line_po_id: poHeaderData.id,
          unit_price: poLineItemData.unit_price,
          total_price: poLineItemData.po_amount,
          item_costing_method: itemData.material_costing_method,
          line_remark_1: poLineItemData.line_remark_1,
          line_remark_2: poLineItemData.line_remark_2,
          po_line_item_id: poLineItemData.id,
        };

        tableGR.push(newTableGrRecord);
      }

      purchaseOrderNumber.push(poHeaderData.purchase_order_no);
      poId.push(poHeaderData.id);
    }

    poId = [...new Set(poId)];

    await this.setData({
      table_gr: tableGR,
      purchase_order_number: purchaseOrderNumber.join(", "),
      po_id: poId,
    });

    const resCategory = await db
      .collection("blade_dict")
      .where({ code: "inventory_category" })
      .get();

    setTimeout(async () => {
      const table_gr = this.getValue("table_gr");
      for (const [index, gr] of table_gr.entries()) {
        // check item batch field
        const path = `table_gr.${index}.item_batch_no`;
        this.disabled(path, gr.item_batch_no !== "");

        // set inventory category option and default value
        if (gr.inspection_required === "No") {
          if (!putawaySetup || putawaySetup.putaway_required === 0) {
            const invCategoryOption = resCategory.data.filter(
              (cat) =>
                cat.dict_key === "Unrestricted" || cat.dict_key === "Blocked"
            );
            this.setOptionData(
              `table_gr.${index}.inv_category`,
              invCategoryOption
            );

            this.setData({
              [`table_gr.${index}.inv_category`]: "Unrestricted",
            });
          } else if (putawaySetup && putawaySetup.putaway_required === 1) {
            const invCategoryOption = resCategory.data.filter(
              (cat) => cat.dict_key === "In Transit"
            );
            this.setOptionData(
              `table_gr.${index}.inv_category`,
              invCategoryOption
            );

            this.setData({
              [`table_gr.${index}.inv_category`]: "In Transit",
            });

            this.display('assigned_to');
          }
        } else if (gr.inspection_required === "Yes") {
          if (!putawaySetup || putawaySetup.putaway_required === 0) {
            const invCategoryOption = resCategory.data.filter(
              (cat) =>
                cat.dict_key === "Unrestricted" ||
                cat.dict_key === "Blocked" ||
                cat.dict_key === "Quality Inspection"
            );
            this.setOptionData(
              `table_gr.${index}.inv_category`,
              invCategoryOption
            );
          } else if (putawaySetup && putawaySetup.putaway_required === 1) {
            const invCategoryOption = resCategory.data.filter(
              (cat) =>
                cat.dict_key === "In Transit" ||
                cat.dict_key === "Quality Inspection"
            );
            this.setOptionData(
              `table_gr.${index}.inv_category`,
              invCategoryOption
            );
            this.display('assigned_to');
          }

          this.setData({
            [`table_gr.${index}.inv_category`]: "Quality Inspection",
          });
        }
      }
    }, 100);
  }
})();

const page_status = this.getValue("page_status");
const fieldData = arguments[0];
const rowIndex = fieldData.rowIndex;

db.collection("Item")
  .where({ id: fieldData.value })
  .get()
  .then((res) => {
    console.log("res Junaaaa", res);
    const itemData = res.data[0];
    if (itemData) {
      const batchManagementEnabled =
        itemData.item_batch_management === 1 ||
        itemData.item_batch_management === true ||
        itemData.item_batch_management === "1";

      if (batchManagementEnabled) {
        this.disabled(`table_gr.${rowIndex}.item_batch_no`, false);
        if (page_status === "Add") {
          this.setData({ [`table_gr.${rowIndex}.item_batch_no`]: "" });
