        });

        dialogData = {
          [`dialog_serial_number.item_id`]: itemData.id || materialId,
          [`dialog_serial_number.item_code`]: itemData.material_code || "",
          [`dialog_serial_number.item_name`]: itemData.material_name || "",
          [`dialog_serial_number.row_index`]: rowIndex,
