// Helper function to round quantity to 3 decimal places
const roundQty = (value) => {
  return Math.round(value * 1000) / 1000;
};

(async () => {
  try {
    // Get input values
    const quantity = arguments[0].value;
    const rowIndex = arguments[0].rowIndex;

    // Validate inputs
    if (rowIndex === undefined || rowIndex === null) {
      console.error("Row index is missing");
      return;
    }

    if (quantity === undefined || quantity === null) {
      console.error("Quantity value is missing");
      return;
    }

    // Check if line has HU data - if quantity changed, confirm reset
    const tempHuDataStr = this.getValue(`table_gr.${rowIndex}.temp_hu_data`);
    const uomConversionCheck =
      this.getValue(`table_gr.${rowIndex}.uom_conversion`) || 1;

    if (tempHuDataStr && tempHuDataStr !== "[]") {
      const tempHuData = JSON.parse(tempHuDataStr);
      const totalStoreInQty = tempHuData.reduce(
        (sum, hu) => sum + (parseFloat(hu.store_in_quantity) || 0),
        0
      );

      // Convert totalStoreInQty to base UOM for comparison
      const totalStoreInBaseQty = totalStoreInQty * uomConversionCheck;

      // If new quantity differs from HU total (in base UOM), warn user
      if (quantity !== totalStoreInBaseQty) {
        try {
          await this.$confirm(
            "Changing the received quantity will reset the selected Handling Units. Do you want to continue?",
            "Warning",
            {
              confirmButtonText: "Yes",
              cancelButtonText: "No",
              type: "warning",
            }
          );

          // User confirmed - clear temp_hu_data and view_hu
          await this.setData({
            [`table_gr.${rowIndex}.temp_hu_data`]: "[]",
            [`table_gr.${rowIndex}.view_hu`]: "",
          });
        } catch {
          // User cancelled - revert to HU total (in base UOM)
          await this.setData({
            [`table_gr.${rowIndex}.base_received_qty`]: totalStoreInBaseQty,
          });
          return;
        }
      }
    }

    // Skip calculation for hierarchy split parent rows (their quantities are managed by split logic)
    // Note: Split-Parent rows are treated like regular rows (no skip)
    const isSplit = this.getValue(`table_gr.${rowIndex}.is_split`);
    const parentOrChild = this.getValue(`table_gr.${rowIndex}.parent_or_child`);
    if (isSplit === "Yes" && parentOrChild === "Parent") {
      return;
    }

    // Split-Parent rows: treat like regular rows (fall through to regular logic)
    // They are independent and can have their own quantities validated normally

    // For child rows: validate total children qty against parent's ordered qty
    if (parentOrChild === "Child") {
      const uomConversion =
        this.getValue(`table_gr.${rowIndex}.uom_conversion`) || 0;
      const receivedQty = roundQty(
        uomConversion > 0 ? quantity / uomConversion : quantity
      );

      const parentIndex = this.getValue(`table_gr.${rowIndex}.parent_index`);
      const tableGR = this.getValue("table_gr");

      // Find parent row to get ordered_qty
      const parentRow = tableGR.find(
        (row) =>
          row.is_split === "Yes" &&
          row.parent_or_child === "Parent" &&
          row.parent_index === parentIndex
      );

      if (parentRow) {
        const parentOrderedQty = parseFloat(parentRow.ordered_qty) || 0;
        const parentInitialReceivedQty =
          parseFloat(parentRow.initial_received_qty) || 0;
        const parentRemainingQty = parentOrderedQty - parentInitialReceivedQty;

        // Get all sibling children (excluding current row)
        const siblingChildren = tableGR.filter(
          (row, idx) =>
            row.parent_or_child === "Child" &&
            row.parent_index === parentIndex &&
            idx !== rowIndex
        );

        // Sum siblings' received_qty
        const siblingsTotal = siblingChildren.reduce(
          (sum, child) => sum + (parseFloat(child.received_qty) || 0),
          0
        );

        // Total with new value
        const totalChildrenQty = roundQty(siblingsTotal + receivedQty);

        // Get tolerance from item
        const itemId = this.getValue(`table_gr.${rowIndex}.item_id`);
        let overReceiveTolerance = 0;

        if (itemId) {
          const { data: itemData } = await db
            .collection("Item")
            .where({ id: itemId })
            .get();
          if (itemData && itemData.length > 0) {
            overReceiveTolerance = itemData[0].over_receive_tolerance || 0;
          }
        }

        // Calculate max allowed with tolerance
        const maxAllowedQty = roundQty(
          (parentRemainingQty * (100 + overReceiveTolerance)) / 100
        );

        // Validate
        if (totalChildrenQty > maxAllowedQty) {
          this.$message.warning(
            `Total split quantity (${totalChildrenQty}) exceeds maximum allowed (${maxAllowedQty}).`
          );
        }
      }

      const currentChildReceivedQty =
        this.getValue(`table_gr.${rowIndex}.received_qty`) || 0;
      if (currentChildReceivedQty !== receivedQty) {
        await this.setData({
          [`table_gr.${rowIndex}.received_qty`]: receivedQty,
        });
      }
      return;
    }

    // Get table values
    const orderedQty = this.getValue(`table_gr.${rowIndex}.ordered_qty`) || 0;
    const baseOrderedQty =
      this.getValue(`table_gr.${rowIndex}.base_ordered_qty`) || 0;
    const initialReceivedQty =
      this.getValue(`table_gr.${rowIndex}.initial_received_qty`) || 0;
    const uomConversion =
      this.getValue(`table_gr.${rowIndex}.uom_conversion`) || 0;
    const currentReceivedQty =
      this.getValue(`table_gr.${rowIndex}.received_qty`) || 0;

    // Fetch over-receive tolerance from Item master
    const itemId = this.getValue(`table_gr.${rowIndex}.item_id`);
    let overReceiveTolerance = 0;

    if (itemId) {
      const { data: itemData } = await db
        .collection("Item")
        .where({ id: itemId })
        .get();
      if (itemData && itemData.length > 0) {
        overReceiveTolerance = itemData[0].over_receive_tolerance || 0;
      }
    }

    console.log("Calculation inputs:", {
      quantity,
      rowIndex,
      orderedQty,
      baseOrderedQty,
      initialReceivedQty,
      uomConversion,
      overReceiveTolerance,
    });

    // Handle negative quantity
    if (quantity < 0) {
      console.warn("Negative base quantity entered");
      this.$message.error("Quantity cannot be negative");

      const toReceivedQty = orderedQty - initialReceivedQty;
      await this.setData({
        [`table_gr.${rowIndex}.base_received_qty`]: 0,
        [`table_gr.${rowIndex}.received_qty`]: 0,
        [`table_gr.${rowIndex}.to_received_qty`]: toReceivedQty,
      });
      return;
    }

    // Calculate base initial received qty for validation
    const baseInitialReceivedQty =
      uomConversion > 0
        ? roundQty(initialReceivedQty * uomConversion)
        : initialReceivedQty;

    // Calculate max allowed base qty with over-receive tolerance
    const maxAllowedBaseQty = roundQty(
      (baseOrderedQty * (100 + overReceiveTolerance)) / 100
    );

    // Validate and cap if exceeds max allowed
    let effectiveBaseQty = quantity;

    if (roundQty(quantity + baseInitialReceivedQty) > maxAllowedBaseQty) {
      effectiveBaseQty = roundQty(maxAllowedBaseQty - baseInitialReceivedQty);

      console.warn(
        `Base quantity (${quantity}) exceeds max allowed (${maxAllowedBaseQty - baseInitialReceivedQty}) with ${overReceiveTolerance}% tolerance`
      );

      this.$message.warning(
        `Base received quantity adjusted to maximum allowed: ${effectiveBaseQty} (${overReceiveTolerance}% over-receive tolerance).`
      );

      await this.setData({
        [`table_gr.${rowIndex}.base_received_qty`]: effectiveBaseQty,
      });
    }

    // Convert base to alt UOM
    const receivedQty = roundQty(
      uomConversion > 0 ? effectiveBaseQty / uomConversion : effectiveBaseQty
    );

    // Calculate remaining qty in alt UOM
    const toReceivedQty = roundQty(
      orderedQty - receivedQty - initialReceivedQty
    );

    const updates = {
      [`table_gr.${rowIndex}.to_received_qty`]: toReceivedQty < 0 ? 0 : toReceivedQty,
    };
    if (currentReceivedQty !== receivedQty) {
      updates[`table_gr.${rowIndex}.received_qty`] = receivedQty;
    }
    await this.setData(updates);
  } catch (error) {
    console.error("Error in quantity calculation:", error);

    // Log additional error details
    if (error.stack) {
      console.error("Stack trace:", error.stack);
    }

    this.$message.error(
      "An error occurred while calculating quantities. Please try again.",
    );
  }
})();

(async () => {
  await this.openDialog("dialog_formula");

  const rowData = arguments[0].row;

  console.log("rowData", rowData);

  this.setData({
    [`dialog_formula.item_id`]: rowData.item_id,
    [`dialog_formula.item_name`]: rowData.item_id,
    [`dialog_formula.formula`]: rowData.formula,
    [`dialog_formula.based_uom`]: rowData.base_ordered_qty_uom,
  });

  const formula = rowData.formula;

  const withoutParens = formula.replace(/\(|\)/g, "");
  const operatorPattern = /(\+|-|\*|\/|\^2|\^3)/;
  let variableList = [];

  const elements = withoutParens
    .split(operatorPattern)
    .filter((item) => item.trim() !== "");

  for (const [index, item] of elements.entries()) {
    elements[index] = item.replace(/\{|\}/g, "");
  }

  console.log("elements", elements);

  for (const item of elements) {
    if (!operatorPattern.test(item) && !(/^-?\d*\.?\d+$/.test(item))) {
      variableList.push({
        formula_variable: item,
        value: 0,
      });
    }
  }

  this.setData({ [`dialog_formula.table_formula`]: variableList });
})();

(async () => {
  const formulaData = this.getValue(`dialog_formula.table_formula`);
  const formula = this.getValue(`dialog_formula.formula`);

  const filterFormulaData = formulaData.filter(
    (item) => item.formula_value && item.formula_value !== ""
  );
  if (formulaData.length !== filterFormulaData.length) {
    await this.$alert(
      "Please input all value.",
      "Insufficient Information Detected",
      {
        confirmButtonText: "Ok",
        type: "error",
      }
    );

    return;
  }

  let withoutBraces = formula.replace(/\{|\}/g, "");
  for (const item of formulaData) {
    withoutBraces = withoutBraces.replace(
      item.formula_variable,
      item.formula_value
    );
  }

  console.log("withoutBraces", withoutBraces);
  // Fix 1: Better power operator replacement that handles numbers after operators
  let formattedFormula = withoutBraces.replace(
    /(\d+(?:\.\d+)?)\^2/g,
    "Math.pow($1, 2)"
  );
  formattedFormula = formattedFormula.replace(
    /(\d+(?:\.\d+)?)\^3/g,
    "Math.pow($1, 3)"
  );

  // Fix 2: Also handle cases where the power operator follows a closing parenthesis
  formattedFormula = formattedFormula.replace(/(\))\^2/g, "$1**2");
  formattedFormula = formattedFormula.replace(/(\))\^3/g, "$1**3");

  console.log("formattedFormula", formattedFormula);
  const result = new Function("return " + formattedFormula)();

  console.log("result", result);

  this.setData({ [`dialog_formula.formula_result`]: result });
})();

