  const predefinedData = [
    {
      putawaySetup: putawaySetup,
      defaultStorageLocation: defaultStorageLocation,
      defaultBinLocation: defaultBinLocation,
      invCategory: invCategory,
    },
  ];

  return predefinedData;
};

